const today = new Date().toISOString().split('T')[0];
const allItems = $input.all();

const todaysCoupons = allItems.filter(item => {
  const createdAt = item.json.CreatedAt || '';
  return createdAt.startsWith(today);
});

const totalIssued = todaysCoupons.length;
const totalExpired = todaysCoupons.filter(i => i.json.Status === 'EXPIRED').length;
const totalActive = todaysCoupons.filter(i => i.json.Status === 'ACTIVE').length;

const tableRows = todaysCoupons.map(i => {
  const c = i.json;
  const statusColor = c.Status === 'EXPIRED' ? '#e94560' : '#2ecc71';
  return `<tr style="border-bottom:1px solid rgba(255,255,255,0.08)">
    <td style="padding:8px 6px;font-family:monospace;color:#e94560">${c.CouponCode || '-'}</td>
    <td style="padding:8px 6px">${c.UserName || '-'}</td>
    <td style="padding:8px 6px">${c.UserEmail || '-'}</td>
    <td style="padding:8px 6px;text-align:center">${c.DiscountPercent || '-'}%</td>
    <td style="padding:8px 6px;text-align:center"><span style="color:${statusColor};font-weight:bold">${c.Status || '-'}</span></td>
    <td style="padding:8px 6px;font-size:12px;color:#aaa">${c.ExpiresAt || '-'}</td>
  </tr>`;
}).join('');

const tableHtml = totalIssued > 0 ? `
<table style="width:100%;border-collapse:collapse;font-size:13px">
  <thead>
    <tr style="border-bottom:2px solid rgba(255,255,255,0.2)">
      <th style="padding:8px 6px;text-align:left;color:#aaa;font-weight:normal">Code</th>
      <th style="padding:8px 6px;text-align:left;color:#aaa;font-weight:normal">Name</th>
      <th style="padding:8px 6px;text-align:left;color:#aaa;font-weight:normal">Email</th>
      <th style="padding:8px 6px;text-align:center;color:#aaa;font-weight:normal">Disc.</th>
      <th style="padding:8px 6px;text-align:center;color:#aaa;font-weight:normal">Status</th>
      <th style="padding:8px 6px;text-align:left;color:#aaa;font-weight:normal">Expires</th>
    </tr>
  </thead>
  <tbody>${tableRows}</tbody>
</table>` : '<p style="color:#aaa;text-align:center">No coupons issued today.</p>';

return [{
  json: {
    today,
    totalIssued,
    totalExpired,
    totalActive,
    tableHtml,
    summaryLine: `${totalIssued} issued, ${totalExpired} expired, ${totalActive} still active`
  }
}];
